pub fn katex_glyph_metrics(ch: char, font: FontStyle) -> Option<&'static KaTeXMetrics> {
    let code = ch as u32;
    match font {
        FontStyle::MathItalic => MATH_ITALIC.get(&code),
        FontStyle::MainRegular => MAIN_REGULAR.get(&code),
    }
}
